import React from 'react';
import styled from 'styled-components';
import personalInfo from '../../data/personalInfo';
import socialLinks from '../../data/socialLinks';
import resumeData from '../../data/resumeData';
import { ResumeBanner } from './ResumeBanner';
import { WorkExperience } from './WorkExperience';
import { Education } from './Education';
import { Skills } from './Skills';

const ResumeContainer = styled.div`
  position: relative;
  border: solid 2px #bbbbbb;
  background-color: #eeeeee;
  margin: 0% 0% 0% 50%;
  border-radius: 5px 5px 0px 0px;
  width: 8.5in;
  transform: translate(-50%, 0%);

  @media (max-width: 900px) {
    width: 6.375in;
  }
  @media (max-width: 660px) {
    width: 4.25in;
  }
  @media print {
    position: absolute;
    display: block;
    width: 100%;
    margin: 0;
    padding: 0;
    left: 0;
    top: 0;
    border: none;
    background-color: #FFF;
    border-radius: 0;
    transform: none;
  }
`;

const ResumeBody = styled.div`
  background-color: #FFF;
  padding: .5in;
  -webkit-text-size-adjust: none;

  @media (max-width: 900px) {
    padding: .6in;
  }
  @media (max-width: 660px) {
    padding: .4in;
  }
  @media print {
    padding: .5in;
  }
`;

const PrintHeader = styled.div`
  height: 2.5em;
  @media print {
    display: none;
  }
`;

const PrintIcon = styled.img`
  float: right;
  width: 25px;
  margin: .5em;
  cursor: pointer;
`;

const handlePrint = () => window.print();

export const Resume = () => {
  return (
    <div>
      <ResumeContainer>
        <PrintHeader>
          <PrintIcon src="print.png" alt="Print resume" onClick={handlePrint} />
        </PrintHeader>
        <ResumeBody>
          <ResumeBanner personalInfo={personalInfo} socialLinks={socialLinks} />
          <WorkExperience jobs={resumeData.workExperience} />
          <Education degrees={resumeData.education} />
          <Skills skills={resumeData.skills} />
        </ResumeBody>
      </ResumeContainer>
    </div>
  );
};
